    if not data or not data[0]:
        return data

    lines = data.splitlines()
    rows, cols = map(int, lines[0].split())
    matrix = [list(map(int, line.split())) for line in lines[1:rows + 1]]

    zero_rows = set()
    zero_cols = set()

    for i in range(rows):
        for j in range(cols):
            if matrix[i][j] == 0:
                zero_rows.add(i)
                zero_cols.add(j)

    for i in zero_rows:
        for j in range(cols):
            matrix[i][j] = 0

    for j in zero_cols:
        for i in range(rows):
            matrix[i][j] = 0

    return [' '.join(map(str, row)) for row in matrix]

