function setMatrixZeroes(data) {
    const lines = data.trim().split('\n');
    const [m, n] = lines[0].split(' ').map(Number);
    const matrix = lines.slice(1).map(line => line.split(' ').map(Number));
    const zeroRows = new Set();
    const zeroCols = new Set();
    // First pass: find all the rows and columns that need to be zeroed
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (matrix[i][j] === 0) {
                zeroRows.add(i);
                zeroCols.add(j);
            }
        }
    }
    // Second pass: set the marked rows and columns to zero
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (zeroRows.has(i) || zeroCols.has(j)) {
                matrix[i][j] = 0;
            }
        }
    }
    return matrix.map(row => row.join(' ')).join('\n');
}

