        int rows = data.length;
        int cols = data[0].length;
        int[][] temp = new int[rows][cols];
        // Mark the positions of zeros in the temporary matrix
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                if (data[i][j] == 0) {
                    temp[i][j] = 1;
                }
            }
        }
        // Set the marked rows and columns to zero in the original matrix
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                if (temp[i][j] == 1) {
                    for (int k = 0; k < cols; k++) {
                        data[i][k] = 0;
                    }
                    for (int k = 0; k < rows; k++) {
                        data[k][j] = 0;
                    }
                }
            }
        }
    }
}

